package com.evolua.user.application; import com.evolua.user.domain.Profile; import com.evolua.user.domain.ProfileRepository; import java.time.Instant; import java.util.List; import org.springframework.stereotype.Service; @Service public class ProfileService { private final ProfileRepository repository; public ProfileService(ProfileRepository repository) { this.repository = repository; } public Profile create(String userId, String displayName, String bio, Integer journeyLevel, Boolean premium) { return repository.save(new Profile(null, userId, displayName, bio, journeyLevel, premium, Instant.now())); } public List<Profile> list(String userId) { return repository.findAllByUserId(userId); } }
